settings.customCss:
/* === Container === */
.mfdr-wrap, .mfdr-golf-leaderboard {
  max-width: 1100px;
  margin: 0 auto;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Helvetica, Arial, sans-serif;
}

/* === Toolbar === */
.mfdr-toolbar { display: flex; justify-content: flex-end; padding: 6px 0; }
.mfdr-export-btn {
  background: #fff; color: #555; border: 1px solid #ccc; padding: 4px 10px;
  font-size: 12px; cursor: pointer; border-radius: 3px;
}

/* === Group accordion (Flight) — soft blue header === */
.mfdr-group { margin-bottom: 4px; border: 1px solid #b8c8d8; }
.mfdr-group-hdr {
  background: linear-gradient(180deg, #6e93b6 0%, #5a7d9e 100%);
  color: #fff;
  padding: 8px 14px;
  font-weight: 500;
  font-size: 13px;
  cursor: pointer;
  user-select: none;
}
.mfdr-group-hdr:hover { background: linear-gradient(180deg, #5a7d9e 0%, #486a8a 100%); }
.mfdr-group-arrow { display: inline-block; margin-right: 6px; font-size: 9px; }
.mfdr-group-count { opacity: 0.9; margin-left: 6px; font-weight: 400; }

/* === Leaderboard table === */
.mfdr-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
  background: #fff;
}
.mfdr-table thead th {
  background: #fff;
  color: #555;
  text-align: center;
  padding: 8px 6px;
  font-weight: 600;
  font-size: 12px;
  border-bottom: 2px solid #d4dce4;
}
.mfdr-table tbody td {
  padding: 8px;
  text-align: center;
  border-bottom: 1px solid #e6eaed;
  vertical-align: middle;
  color: #333;
}
.mfdr-table tbody tr:hover { background: #f5f9fc; }
.mfdr-table tbody td:nth-child(1) { color: #555; width: 50px; }
.mfdr-table tbody td:nth-child(2) { text-align: left; padding-left: 14px; }
.mfdr-table .mfdr-drill { color: #2980b9; text-decoration: none; cursor: pointer; }
.mfdr-table .mfdr-drill:hover { text-decoration: underline; }

/* === Inline drill === */
.mfdr-detail-row { background: #fafbfc; }
.mfdr-detail-content { padding: 6px 0; }

/* === Per-round block === */
.mfgs-round { margin-bottom: 0; border: 0; background: #fff; }
.mfgs-round-hdr {
  background: #f0f3f6;
  padding: 6px 12px;
  font-size: 12px;
  text-align: center;
  cursor: pointer;
  border-top: 1px solid #d4dce4;
  border-bottom: 1px solid #d4dce4;
}
.mfgs-round-hdr strong {
  color: #2c3e50;
  font-weight: 600;
}
.mfgs-round-hdr em {
  color: #6a7a82;
  font-style: italic;
  margin-left: 6px;
  font-size: 11px;
  font-weight: normal;
}
.mfgs-arrow { display: none; }

/* SLIM mode (Mock 1) — hide Yardage/Par/SI/Slope rows, only score row visible */
.mfgs-slope,
.mfgs-yardage,
.mfgs-par-row,
.mfgs-si-row { display: none !important; }
.mfgs-hidden { display: none; }

/* === Scorecard table === */
.mfgs-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
  background: #fff;
}
.mfgs-table thead th {
  background: #fff;
  color: #555;
  font-weight: 500;
  padding: 4px 3px;
  text-align: center;
  border: 1px solid #e6eaed;
  font-size: 11px;
}
.mfgs-table td {
  padding: 5px 3px;
  text-align: center;
  border: 1px solid #e6eaed;
  font-size: 13px;
  color: #333;
}
.mfgs-sep { background: #f0f3f6 !important; font-weight: 600; }

/* Player row label */
.mfgs-score-row .mfgs-player-cell,
.mfgs-table .mfgs-player-cell {
  text-align: left !important;
  color: #2980b9;
  font-weight: 500;
  padding-left: 10px !important;
  white-space: nowrap;
}

/* === SCORE COLOR MARKS — exact GolfGenius style ===
   simple_circle = birdie (1 under par) — red CIRCLE outline
   double_circle = eagle (2+ under par) — red CIRCLE with double outline
   par           = plain text, no decoration
   simple_square = bogey (1 over par) — navy SQUARE outline
   double_square = dbl bogey (2+ over par) — navy SQUARE with double outline
*/
.mfgs-mark {
  display: inline-block;
  min-width: 22px;
  height: 22px;
  line-height: 19px;
  text-align: center;
  font-weight: 600;
  font-size: 13px;
  position: relative;
  box-sizing: border-box;
}
.mfgs-birdie {
  border: 1.5px solid #c0392b;
  border-radius: 50%;
  color: #c0392b;
  padding: 0 2px;
  min-width: 22px;
  width: 22px;
}
.mfgs-eagle {
  border: 1.5px solid #c0392b;
  border-radius: 50%;
  color: #c0392b;
  padding: 0 2px;
  min-width: 22px;
  width: 22px;
  box-shadow: inset 0 0 0 2px #fff, inset 0 0 0 3.5px #c0392b;
}
.mfgs-par {
  color: #333;
  border: none;
}
.mfgs-bogey {
  border: 1.5px solid #2c3e50;
  border-radius: 0;
  color: #2c3e50;
  padding: 0 2px;
  min-width: 22px;
  width: 22px;
}
.mfgs-dblbogey {
  border: 1.5px solid #2c3e50;
  border-radius: 0;
  color: #2c3e50;
  padding: 0 2px;
  min-width: 22px;
  width: 22px;
  box-shadow: inset 0 0 0 2px #fff, inset 0 0 0 3.5px #2c3e50;
}

.mfgs-total {
  background: #2c3e50 !important;
  color: #fff !important;
  font-weight: 600;
}
.mfgs-round + .mfgs-round { border-top: 0; }
.mfdr-detail-content > .mfgs-round { margin: 0; }
